if (!msg.job_id) { node.error('msg.job_id required', msg); return null; }
msg._wj = {
    job_id: msg.job_id,
    poll_interval_ms: msg.poll_interval_ms || 5000,
    deadline: Date.now() + (msg.timeout_ms || 86400000),
    last_state: null
};
msg.method = 'GET';
msg.path = '/v1/clusters/{cluster_id}/jobs/{job_id}';
return msg;

const TERMINAL = ['COMPLETED','FAILED','CANCELLED','TIMEOUT','NODE_FAIL','OUT_OF_MEMORY','BOOT_FAIL','DEADLINE'];
const body = msg.payload || {};
const state = body.state || (body.job && body.job.state) || 'UNKNOWN';
msg._wj = msg._wj || {};
let transitionMsg = null;
if (state !== msg._wj.last_state) {
    transitionMsg = { payload: { job_id: msg._wj.job_id, state: state, prev: msg._wj.last_state, body: body } };
    msg._wj.last_state = state;
}
if (TERMINAL.includes(state)) {
    return [{ payload: { job_id: msg._wj.job_id, state: state, body: body } }, transitionMsg, null];
}
if (Date.now() > msg._wj.deadline) {
    return [{ payload: { job_id: msg._wj.job_id, state: 'TIMEOUT_LOCAL', body: body } }, transitionMsg, null];
}
// keep polling
return [null, transitionMsg, msg];

msg.delay = msg._wj.poll_interval_ms;
msg.method = 'GET';
msg.path = '/v1/clusters/{cluster_id}/jobs/{job_id}';
msg.job_id = msg._wj.job_id;
return msg;
